import{_ as r,r as n,o as a,c as l,b as t,d as e,e as s,a as i}from"./app-2a089349.js";const c={},d=i('<h1 id="um-stripe-plan-settings" tabindex="-1"><a class="header-anchor" href="#um-stripe-plan-settings" aria-hidden="true">#</a> UM Stripe Plan Settings</h1><p>This article serves as a comprehensive guide for configuring the Ultimate Member Stripe Plan Settings, ensuring seamless and tailored integration with your Stripe.com products or subscriptions</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6b90b52a6af5def3c8ea9/file-ZPl8Z05MzC.png" alt=""></p><p>In the <strong>wp-admin&gt;Ultimate Member&gt;Stripe Plans&gt; Add or Edit a plan</strong>, you have the options to set up the following:</p><ul><li><strong>Plan Title</strong> - The plan or product title entered in this field will be displayed as an option in the Stripe Plan field of the form.</li><li><strong>Setup Subscription</strong> -This is where you can configure the following options:</li></ul><table><thead><tr><th></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>This option allows you to choose your preferred subscription plan type. If prices are imported from your Stripe account, it only displays the product payment type, and you&#39;ll be unable to edit it. If you set up the Stripe Plan in Ultimate Member, you can choose whether your product is recurring or one-time. <strong>Recurring:</strong> This streamlines subscription-based payments effortlessly with automated scheduling <strong>One-time</strong>: Securely processes individual transactions, perfect for single purchases, donations, or unique financial interactions.</td></tr><tr><td><strong>Subscription price</strong></td><td>This option allows you to select from the Imported Subscription Price from your Stripe Account. If prices are imported from your Stripe account, it only displays the product prices you&#39;ve created in Stripe, and you&#39;ll be unable to select from the prices. If you set up the Stripe Plan in Ultimate Member, you can choose which imported subscription price you prefer.</td></tr><tr><td>Roles:</td><td>Assign a role to each <a href="/docs-v3/um-stripe/article/1616-stripe-shortcodes-reference">Stripe Events</a> .</td></tr><tr><td><strong>Active Role</strong></td><td>This option enables you to choose the role to assign when a subscription is <strong>active</strong></td></tr><tr><td><strong>Unpaid Role</strong></td><td>This option enables you to choose the role to assign when a subscription is <strong>unpaid</strong></td></tr><tr><td><strong>Paused Role</strong></td><td>This option enables you to choose the role to assign when a subscription is <strong>paused</strong></td></tr><tr><td><strong>Past Due Role</strong></td><td>This option enables you to choose the role to assign when a subscription is <strong>past due</strong></td></tr><tr><td><strong>Canceled Role</strong></td><td>This option enables you to choose the role to assign when a subscription is <strong>canceled</strong></td></tr><tr><td><strong>Trialing Role</strong></td><td>This option enables you to choose the role to assign when a subscription is on <strong>trial</strong></td></tr><tr><td><strong>Trial Periods</strong></td><td>This option enables you to specify the trial period duration in days for your subscription plan. It determines the default number of trial days when enrolling a customer, activating the trial functionality of the subscription plan. This setting will always override any trials associated with a subscribed plan. Ensure the trial end value is set to a minimum of 2 days.</td></tr><tr><td><strong>Display Promotion Code field on Stripe Checkout form</strong></td><td>When enabled, customers can enter a promotion code on the Stripe Checkout form. However, if the pricing model for your product in Stripe.com is set to &#39;customer chooses price&#39; with an adjustable amount enabled in the Price settings, this option will be disabled during the checkout process</td></tr></tbody></table><p>The image below illustrates how the Promotion Code functions in the Stripe Checkout Form:</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65831ae52e3a566b03b69bce/file-mGLK2Dm6ox.png" alt=""></p>',8),u=i('<li><strong>Create Section</strong> - In this section, you have the option to set the Stripe Plan as a draft, edit, create, update, or delete. <ul><li><strong>Status</strong>: You can select and set the status of your plan to publish, pending review, or draft.</li><li><strong>Visibility</strong> -You can select and set the visibility of your plan to public, password-protected, or private.</li><li><strong>Publish</strong> - You can select to publish the plan immediately or edit the published date and time.</li></ul></li><li><strong>Shortcode Section</strong> - The <a href="/docs-v3/um-stripe/article/1616-stripe-shortcodes-reference">shortcode</a> generates a button for customers to check out and subscribe to your Stripe plan.</li>',2),h=t("strong",null,"Subscribe URL Section",-1),p=t("strong",null,"Short",-1),g={href:"https://ultimate-member-32612-8491614.umsites.net/?um_stripe_plan_id=51",target:"_blank",rel:"noopener noreferrer"},m=t("strong",null,"Hashed",-1),b={href:"https://ultimate-member-32612-8491614.umsites.net/stripe/",target:"_blank",rel:"noopener noreferrer"},f={href:"https://um.x/checkout/OTg3MmVkOWZjMjJmYzE4MmQzNzFjM2U5ZWQzMTYwOTQ",target:"_blank",rel:"noopener noreferrer"},y=i('<hr><h3 id="customize-the-slug-of-the-subscribe-url" tabindex="-1"><a class="header-anchor" href="#customize-the-slug-of-the-subscribe-url" aria-hidden="true">#</a> Customize the slug of the Subscribe URL</h3><p>The default URL slug is yoursitedomain.com/ stripe/--random hash ID--/. To customize the slug of the Subscribe URL, do the following steps:</p><ul><li>Go to <strong>wp-Admin &gt; Pages &gt;Hover to UM Stripe Checkout page&gt; Click on &quot;Quick Edit</strong>&quot; <img src="" alt=""></li><li>Type your preferred slug in the field.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/651db292c00c2b65208e1c82/file-VQ0SaN8bsz.png" alt=""></li><li>Click the Update button to save. When you visit the page, you&#39;ll notice the modified slug in the Stripe Checkout URL. If there is no URL parameter or if the URL parameter is wrong, the page will be inaccessible and will redirect to the homepage. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/651db77a42d97d1c0459145f/file-yZAx80VqBx.png" alt=""></li></ul>',4);function S(_,w){const o=n("ExternalLinkIcon");return a(),l("div",null,[d,t("ul",null,[u,t("li",null,[h,e(" - The URLs are auto-generated once you import the price from your Stripe account. The URL will redirect users to the Stripe Checkout with your Stripe plan. "),t("ul",null,[t("li",null,[p,e(" - This subscribe URL includes the stripe plan ID e.g. "),t("a",g,[e("https://ultimate-member-32612-8491614.umsites.net?um_stripe_plan_id=51"),s(o)])]),t("li",null,[m,e(" - This subscribe URL is a hashed URL to prevent the post_id from being exposed. The created Stripe Checkout Page, when you activated the UM Stripe plugin, is to hold the generated hashed as a Subscribe URL. e.g. "),t("a",b,[e(" https://ultimate-member-32612-8491614.umsites.net/stripe/"),s(o)]),e(),t("a",f,[e("OTg3MmVkOWZjMjJmYzE4MmQzNzFjM2U5ZWQzMTYwOTQ"),s(o)])])])])]),y])}const v=r(c,[["render",S],["__file","1892-stripe-plan-settings.html.vue"]]);export{v as default};
